#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1000005;;
string s;
int	t,n,len[N],mx,mid,ans[N];
queue<int> q; 
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t;
	while(t--)
	{
		cin>>s;
		n=s.size();
		s=" "+s;
		mx=mid=0;
		for(int i=1;i<=n;i++)
		{
			if(mx>i)
			{
				len[i]=min(len[2*mid-i],mx-i);
			}
			else len[i]=1;
			while(s[i+len[i]]==s[i-len[i]])
			{
				len[i]++;
			}
			if(i+len[i]>mx)
			{
				mx=i+len[i];
				mid=i;
			}
//			len[i]/=2;
			len[i]--;
//			cout<<len[i]<<" ";
		}
//		cout<<"\n";
		for(int i=n/2+1;i<=n;i++)
		{
			if(len[i]>=min(i-1,n-i))
			{
				q.push(i);
				ans[i]=1;
			}
		}
		while(!q.empty())
		{
			int t=q.front();
			q.pop();
//			cout<<t<<":\n";
			if(t%2==0) continue;
			int num=t/2+1;
//			cout<<" yes "<<num<<" ???\n";
			if(len[num]<num-1) continue;
//			cout<<" yessssss\n";
			if(ans[num]==0)
			{
				q.push(num);
				ans[num]=1;
			}
		}
		for(int i=1;i<=n;i++)
		{
			if(ans[i]) cout<<i<<" ";
			ans[i]=len[i]=0;
		}
		cout<<"\n";
	}

	return 0;
}
